+package http
+
+import (
+	"io"
+	"unsafe"
+)
+
+// Response represents an HTTP response — same as net/http.Response.
+type Response struct {
+	Status        string
+	StatusCode    int
+	Proto         string
+	ProtoMajor    int
+	ProtoMinor    int
+	Header        Header
+	Body          io.ReadCloser
+	ContentLength int64
+}
+
+type RoundTripper interface {
+	RoundTrip(*Request) (*Response, error)
+}
+
+type Client struct {
+	Transport RoundTripper
+}
+
+var DefaultClient = &Client{}
+
+//go:wasmimport env __gomode_fetch
+func gomodeFetch(urlPtr, urlLen, methodPtr, methodLen, bodyPtr, bodyLen, ctPtr, ctLen uint32) uint32
+
+func ptrOf(b []byte) uint32 {
+	if len(b) == 0 {
+		return 0
+	}
+	return uint32(uintptr(unsafe.Pointer(&b[0])))
+}
+
+func doFetch(method, rawurl, body, contentType string) (*Response, error) {
+	urlB := []byte(rawurl)
+	methodB := []byte(method)
+	bodyB := []byte(body)
+	ctB := []byte(contentType)
+
+	respPtr := gomodeFetch(
+		ptrOf(urlB), uint32(len(urlB)),
+		ptrOf(methodB), uint32(len(methodB)),
+		ptrOf(bodyB), uint32(len(bodyB)),
+		ptrOf(ctB), uint32(len(ctB)),
+	)
+
+	return readFetchResponse(uintptr(respPtr)), nil
+}
+
+func readFetchResponse(base uintptr) *Response {
+	status := int(*(*int32)(unsafe.Pointer(base + 4)))
+	ct := readZBString(base + uintptr(zbValueSlot))
+	bodyStr := readZBString(base + uintptr(2*zbValueSlot))
+
+	resp := &Response{
+		StatusCode:    status,
+		Status:        itoa(status) + " " + StatusText(status),
+		Proto:         "HTTP/1.1",
+		ProtoMajor:    1,
+		ProtoMinor:    1,
+		Header:        Header{},
+		Body:          &stringReader{s: bodyStr},
+		ContentLength: int64(len(bodyStr)),
+	}
+	if ct != "" {
+		resp.Header.Set("Content-Type", ct)
+	}
+	return resp
+}
+
+func readBody(body io.Reader) string {
+	if body == nil {
+		return ""
+	}
+	buf := make([]byte, 0, 4096)
+	tmp := make([]byte, 1024)
+	for {
+		n, err := body.Read(tmp)
+		if n > 0 {
+			buf = append(buf, tmp[:n]...)
+		}
+		if err != nil {
+			break
+		}
+	}
+	return string(buf)
+}
+
+func Get(url string) (*Response, error) {
+	return DefaultClient.Get(url)
+}
+
+func Post(url, contentType string, body io.Reader) (*Response, error) {
+	return DefaultClient.Post(url, contentType, body)
+}
+
+func Head(url string) (*Response, error) {
+	return DefaultClient.Head(url)
+}
+
+func (c *Client) Get(url string) (*Response, error) {
+	return doFetch(MethodGet, url, "", "")
+}
+
+func (c *Client) Head(url string) (*Response, error) {
+	return doFetch(MethodHead, url, "", "")
+}
+
+func (c *Client) Post(url, contentType string, body io.Reader) (*Response, error) {
+	return doFetch(MethodPost, url, readBody(body), contentType)
+}
+
+func (c *Client) Do(req *Request) (*Response, error) {
+	ct := ""
+	if req.Header != nil {
+		ct = req.Header.Get("Content-Type")
+	}
+	return doFetch(req.Method, req.URL.String(), readBody(req.Body), ct)
+}
+
+func NewRequest(method, rawurl string, body io.Reader) (*Request, error) {
+	u := parseRawURL(rawurl)
+	req := &Request{
+		Method:     method,
+		URL:        u,
+		Proto:      "HTTP/1.1",
+		ProtoMajor: 1,
+		ProtoMinor: 1,
+		Header:     Header{},
+		Host:       u.Host,
+	}
+	if body != nil {
+		req.Body = &readerCloser{body}
+	}
+	return req, nil
+}
+
+type readerCloser struct {
+	io.Reader
+}
+
+func (rc *readerCloser) Close() error {
+	return nil
+}

