+func parseRawURL(rawurl string) *URL {
+	u := &URL{}
+	if i := strings.Index(rawurl, "://"); i >= 0 {
+		u.Scheme = rawurl[:i]
+		rawurl = rawurl[i+3:]
+		j := strings.IndexByte(rawurl, '/')
+		if j < 0 {
+			u.Host = rawurl
+			u.Path = "/"
+			return u
+		}
+		u.Host = rawurl[:j]
+		rawurl = rawurl[j:]
+	}
+	if i := strings.IndexByte(rawurl, '#'); i >= 0 {
+		u.Fragment = rawurl[i+1:]
+		rawurl = rawurl[:i]
+	}
+	if i := strings.IndexByte(rawurl, '?'); i >= 0 {
+		u.RawQuery = rawurl[i+1:]
+		rawurl = rawurl[:i]
+	}
+	u.Path = rawurl
+	if u.Path == "" {
+		u.Path = "/"
+	}
+	return u
+}
